package com.seaquake6324.civitas.infrastructure.network;
import com.seaquake6324.civitas.CivitasMod;import java.util.*;import net.minecraft.core.BlockPos;import net.minecraft.network.RegistryFriendlyByteBuf;import net.minecraft.network.codec.StreamCodec;import net.minecraft.network.protocol.common.custom.CustomPacketPayload;import net.minecraft.resources.Identifier;
public record PatrolRouteModePayload(boolean active,List<BlockPos>nodes,int nodeCap,int segmentCap)implements CustomPacketPayload{public PatrolRouteModePayload{nodes=List.copyOf(nodes);}public static final Type<PatrolRouteModePayload>TYPE=new Type<>(Identifier.fromNamespaceAndPath(CivitasMod.MOD_ID,"patrol_route_mode"));public static final StreamCodec<RegistryFriendlyByteBuf,PatrolRouteModePayload>STREAM_CODEC=CustomPacketPayload.codec((p,b)->{b.writeBoolean(p.active);b.writeVarInt(p.nodes.size());p.nodes.forEach(b::writeBlockPos);b.writeVarInt(p.nodeCap);b.writeVarInt(p.segmentCap);},b->{boolean active=b.readBoolean();int size=Math.min(64,b.readVarInt());List<BlockPos>nodes=new ArrayList<>(size);for(int i=0;i<size;i++)nodes.add(b.readBlockPos());return new PatrolRouteModePayload(active,nodes,b.readVarInt(),b.readVarInt());});public static PatrolRouteModePayload stopped(){return new PatrolRouteModePayload(false,List.of(),0,0);}@Override public Type<? extends CustomPacketPayload>type(){return TYPE;}}
